// Wait for widget script to load, then probe the DOM
new Promise(resolve => {
  const check = () => {
    const widget = document.querySelector('elevenlabs-convai');
    const floating = Array.from(document.querySelectorAll('*')).filter(el => {
      const cs = getComputedStyle(el);
      return (cs.position === 'fixed' || cs.position === 'sticky') && parseInt(cs.zIndex) > 5;
    }).slice(0, 20);
    resolve({
      widgetExists: !!widget,
      widgetParent: widget ? widget.parentElement?.tagName + '.' + widget.parentElement?.className?.slice(0,60) : null,
      widgetRect: widget ? widget.getBoundingClientRect().toJSON() : null,
      widgetShadowChildren: widget && widget.shadowRoot ? Array.from(widget.shadowRoot.children).map(c => c.tagName + (c.id ? '#' + c.id : '')) : 'no shadow',
      scriptLoaded: !!document.querySelector('script[src*="convai-widget-embed"]'),
      fixedHighZ: floating.map(el => ({
        tag: el.tagName,
        cls: (el.className || '').toString().slice(0, 80),
        z: getComputedStyle(el).zIndex,
        rect: el.getBoundingClientRect().toJSON(),
        pe: getComputedStyle(el).pointerEvents
      }))
    });
  };
  setTimeout(check, 2500);
});

// Dive into shadow DOM of the widget
const w = document.querySelector('elevenlabs-convai');
const shadow = w.shadowRoot;
const describe = (el) => {
  const r = el.getBoundingClientRect();
  const cs = getComputedStyle(el);
  return {
    tag: el.tagName + (el.id ? '#'+el.id : '') + (el.className ? '.'+(typeof el.className === 'string' ? el.className : el.className.baseVal || '').slice(0,40) : ''),
    rect: { x: r.x|0, y: r.y|0, w: r.width|0, h: r.height|0 },
    pos: cs.position,
    z: cs.zIndex,
    pe: cs.pointerEvents,
    disp: cs.display,
    vis: cs.visibility
  };
};
const all = [w, ...Array.from(shadow.querySelectorAll('*'))];
// Find elements that are actually sized & visible
const sized = all.filter(el => {
  const r = el.getBoundingClientRect();
  return r.width > 5 && r.height > 5 && getComputedStyle(el).visibility !== 'hidden' && getComputedStyle(el).display !== 'none';
});
({
  shadowMode: shadow.mode,
  totalShadowEls: all.length - 1,
  sizedVisible: sized.slice(0, 15).map(describe),
  // Also check if there's a fixed floating button somewhere in viewport
  possibleMicButton: sized.find(el => /button|floating|trigger|toggle|mic|orb/i.test((el.className || '').toString() + el.tagName))?.outerHTML?.slice(0, 200) || 'none',
});

// Scroll the Ben B18 tile into view, return its rect and what's on top of the widget's Start a call button
